window.docContents[240].resolve({"/Diophantine-Equations-and-Transcendence/Newton-polygons-of-p-adic-power-series/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Diophantine-Equations-and-Transcendence--Newton-polygons-of-p-adic-power-series--Valuation-Sequences":{"contents":"The valuation sequence of a power series  over a ring equipped with a map\n to  () is the function\n, , with the\nvalue  (encoded ) marking a zero coefficient. The Newton polygon below is computed\nsolely from this sequence; the -adic instance takes \n(). In Lean this is the type\nNewtonPolygon.ValSeq := ℕ → WithTop ℤ, with toValSeq f v extracting it from an actual\nPowerSeries.\nFormalised in NewtonPolys: NewtonPolygon.ValSeq, NewtonPolygon.toValSeq — sorry-free.\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Diophantine Equations and Transcendence\u0009Newton polygons of p-adic power series","header":"9.7.1. Valuation Sequences","id":"/Diophantine-Equations-and-Transcendence/Newton-polygons-of-p-adic-power-series/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Diophantine-Equations-and-Transcendence--Newton-polygons-of-p-adic-power-series--Valuation-Sequences"},"/Elliptic-Curves-and-Arithmetic-Geometry/Affine-points-and-the-Weierstrass-equation/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elliptic-Curves-and-Arithmetic-Geometry--Affine-points-and-the-Weierstrass-equation":{"contents":"\n\n\n\n\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Elliptic Curves and Arithmetic Geometry","header":"7.5. Affine points and the Weierstrass equation","id":"/Elliptic-Curves-and-Arithmetic-Geometry/Affine-points-and-the-Weierstrass-equation/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Elliptic-Curves-and-Arithmetic-Geometry--Affine-points-and-the-Weierstrass-equation"},"/p-adic-and-Adic-Spaces/Witt-vectors___-tilting___-and-the-Fargues___Fontaine-curve/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--p-adic-and-Adic-Spaces--Witt-vectors___-tilting___-and-the-Fargues___Fontaine-curve--Tilting-and-the-period-ring":{"contents":"Let  be a perfectoid ring () for . Its tilt is the perfection\n\na perfect ring of characteristic . The associated period ring is ,\nthe -typical Witt vectors of the tilt, and Fontaine's theta map is the canonical surjection\n\nwhose kernel is principal, generated by a primitive element of degree \n(). For a perfectoid field the tilt is again a perfectoid field, and\ntilting is an equivalence of categories. Following Scholze, Perfectoid Spaces, §3.\nFormalised in Adic-Spaces: PerfectoidRing.tilt, PerfectoidRing.theta — in progress (surjectivity of theta, theta_surjective, and principality of its kernel, ker_theta_principal, still rest on sorrys).\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009p-adic and Adic Spaces\u0009Witt vectors, tilting, and the Fargues–Fontaine curve","header":"5.15.3. Tilting and the period ring","id":"/p-adic-and-Adic-Spaces/Witt-vectors___-tilting___-and-the-Fargues___Fontaine-curve/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--p-adic-and-Adic-Spaces--Witt-vectors___-tilting___-and-the-Fargues___Fontaine-curve--Tilting-and-the-period-ring"}});